/**
 * Enhanced Queues Page - Phase 1 Implementation
 * Uses Redux Toolkit Query for state management
 */
import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import { getVersionedApiUrl } from '../services/configService';
import {
    Card,
    Table,
    Button,
    Space,
    Tag,
    Row,
    Col,
    message,
    Dropdown,
    Modal,
    Form,
    Input,
    InputNumber,
    Select,
    Switch,
    Divider,
    type TableColumnsType,
} from 'antd';
import {
    PlusOutlined,
    DeleteOutlined,
    EyeOutlined,
    MoreOutlined,
    InboxOutlined,
    SendOutlined,
    UserOutlined,
    SyncOutlined,
    ClearOutlined,
    ReloadOutlined,
} from '@ant-design/icons';
import { useGetQueuesQuery, usePerformQueueOperationMutation } from '../store/api/queuesApi';
import type { Queue, QueueType, QueueStatus, QueueFilters } from '../types/queue';
import StatCard from '../components/common/StatCard';
import FilterBar from '../components/common/FilterBar';
import { showDeleteQueueConfirm, showPurgeConfirm } from '../components/common/ConfirmDialog';
import SetupScopeBar from '../components/common/SetupScopeBar';
import { useManagementStore } from '../stores/managementStore';
import { createQueueUpdatesSSE } from '../services/websocketService';

interface DatabaseSetup {
    setupId: string
    host: string
    port: number
    database: string
    schema: string
}

const QueuesPage: React.FC = () => {
    const { selectedSetupId } = useManagementStore()
    const sseServiceRef = useRef<any>(null)

    const [filters, setFilters] = useState<QueueFilters>({
        page: 1,
        pageSize: 10,
        sortBy: 'name',
        sortOrder: 'asc',
    });

    const [isModalVisible, setIsModalVisible] = useState(false);
    const [setups, setSetups] = useState<DatabaseSetup[]>([]);
    const [setupsLoading, setSetupsLoading] = useState(false);
    const [form] = Form.useForm();

    // Fetch queues using RTK Query — include setup scope from global selector
    const [performQueueOperation] = usePerformQueueOperationMutation();
    const { data, isLoading, isFetching, refetch } = useGetQueuesQuery(
        { ...filters, setupId: selectedSetupId ?? undefined }
    );

    const queues = data?.queues || [];
    const total = data?.total || 0;

    // Calculate summary statistics with defensive programming
    // Use nullish coalescing to handle undefined/null values gracefully
    const totalMessages = queues.reduce((sum, q) => sum + (q.messageCount ?? 0), 0);
    void queues.reduce((sum, q) => sum + (q.consumerCount ?? 0), 0); // totalConsumers - reserved for future use
    const avgMessageRate = queues.length > 0
        ? queues.reduce((sum, q) => sum + (q.messagesPerSecond ?? 0), 0) / queues.length
        : 0;

    // Fetch database setups
    const fetchSetups = useCallback(async () => {
        setSetupsLoading(true);
        try {
            const response = await axios.get(getVersionedApiUrl('setups'));
            if (response.data && Array.isArray(response.data.setupIds)) {
                setSetups(response.data.setupIds.map((setupId: string) => ({
                    setupId,
                    host: 'localhost',
                    port: 5432,
                    database: 'postgres',
                    schema: setupId
                })));
            } else {
                setSetups([]);
            }
        } catch (error) {
            console.error('Failed to fetch database setups:', error);
            setSetups([]);
        } finally {
            setSetupsLoading(false);
        }
    }, []);

    // Load setups on component mount
    useEffect(() => {
        fetchSetups();
    }, [fetchSetups]);

    // Subscribe to live queue updates SSE when a setup is selected
    useEffect(() => {
        if (sseServiceRef.current) {
            sseServiceRef.current.disconnect()
            sseServiceRef.current = null
        }
        if (selectedSetupId) {
            sseServiceRef.current = createQueueUpdatesSSE(
                selectedSetupId,
                () => { refetch() }
            )
        }
        return () => {
            if (sseServiceRef.current) {
                sseServiceRef.current.disconnect()
                sseServiceRef.current = null
            }
        }
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [selectedSetupId]);

    // Handle create queue
    const handleCreateQueue = () => {
        form.resetFields();
        fetchSetups();
        setIsModalVisible(true);
    };

    // Handle modal OK
    const handleModalOk = async () => {
        try {
            const values = await form.validateFields();
            const requestBody = {
                setup: values.setup,
                name: values.name,
                type: values.type ?? 'native',
                visibilityTimeoutSeconds: values.visibilityTimeoutSeconds,
                maxRetries: values.maxRetries,
                deadLetterEnabled: values.deadLetterEnabled,
                batchSize: values.batchSize,
                pollingIntervalSeconds: values.pollingIntervalSeconds,
                fifoEnabled: values.fifoEnabled ?? false,
                deadLetterQueueName: values.deadLetterQueueName || undefined,
            };

            await axios.post(getVersionedApiUrl(`management/queues`), requestBody);
            message.success(`Queue "${values.name}" created successfully`);
            useManagementStore.getState().addNotification({ resource: values.name, action: 'queue created' });

            await refetch();
            setIsModalVisible(false);
            form.resetFields();
        } catch (error: any) {
            const errorMessage = error.response?.data?.message
                || error.response?.data?.error
                || (typeof error.response?.data === 'string' ? error.response?.data : null)
                || error.message
                || 'Failed to create queue';
            message.error(`Failed to create queue: ${errorMessage}`);
        }
    };

    // Handle search
    const handleSearch = (value: string) => {
        setFilters((prev) => ({ ...prev, search: value, page: 1 }));
    };

    // Handle type filter
    const handleTypeFilter = (value: string | string[]) => {
        const types = Array.isArray(value) ? value : value ? [value] : undefined;
        setFilters((prev) => ({
            ...prev,
            type: types as QueueType[] | undefined,
            page: 1,
        }));
    };

    // Handle status filter
    const handleStatusFilter = (value: string | string[]) => {
        const statuses = Array.isArray(value) ? value : value ? [value] : undefined;
        setFilters((prev) => ({
            ...prev,
            status: statuses as QueueStatus[] | undefined,
            page: 1,
        }));
    };

    // Clear all filters
    const handleClearFilters = () => {
        setFilters({
            page: 1,
            pageSize: filters.pageSize,
            sortBy: 'name',
            sortOrder: 'asc',
        });
    };

    // Handle delete queue
    const handleDeleteQueue = (queue: Queue) => {
        showDeleteQueueConfirm(queue.queueName, async () => {
            try {
                await performQueueOperation({
                    setupId: queue.setupId,
                    queueName: queue.queueName,
                    request: { operation: 'DELETE' },
                }).unwrap();
                message.success(`Queue "${queue.queueName}" deleted successfully`);
                useManagementStore.getState().addNotification({ resource: queue.queueName, action: 'queue deleted' });
            } catch (error: any) {
                const errorMessage = error?.data?.error || error?.data?.message || error?.message || 'Failed to delete queue';
                message.error(`Failed to delete queue: ${errorMessage}`);
            }
        });
    };

    // Handle purge queue
    const handlePurgeQueue = (queue: Queue) => {
        showPurgeConfirm(queue.queueName, async () => {
            try {
                await performQueueOperation({
                    setupId: queue.setupId,
                    queueName: queue.queueName,
                    request: { operation: 'PURGE' },
                }).unwrap();
                message.success(`Queue "${queue.queueName}" purged successfully`);
                useManagementStore.getState().addNotification({ resource: queue.queueName, action: 'queue purged' });
            } catch (error: any) {
                const errorMessage = error?.data?.error || error?.data?.message || error?.message || 'Failed to purge queue';
                message.error(`Failed to purge queue: ${errorMessage}`);
            }
        });
    };

    // Action menu for each queue
    const getActionMenu = (queue: Queue) => ({
        items: [
            {
                key: 'view',
                icon: <EyeOutlined />,
                label: <Link to={`/queues/${queue.setupId}/${queue.queueName}`}>View Details</Link>,
            },
            {
                type: 'divider' as const,
            },
            {
                key: 'purge',
                icon: <ClearOutlined />,
                label: 'Purge Messages',
                onClick: () => handlePurgeQueue(queue),
            },
            {
                key: 'delete',
                icon: <DeleteOutlined />,
                label: 'Delete Queue',
                danger: true,
                onClick: () => handleDeleteQueue(queue),
            },
        ],
    });

    // Table columns
    const columns: TableColumnsType<Queue> = [
        {
            title: 'Queue Name',
            dataIndex: 'queueName',
            key: 'queueName',
            sorter: true,
            render: (text: string, record: Queue) => (
                <Space direction="vertical" size="small">
                    <Link
                        to={`/queues/${record.setupId}/${record.queueName}`}
                        style={{ fontWeight: 'bold', fontSize: '14px' }}
                    >
                        {text}
                    </Link>
                    <Space size="small">
                        <Tag color="blue" style={{ fontSize: '11px' }}>
                            {record.setupId}
                        </Tag>
                        <Tag
                            color={
                                record.type === 'native'
                                    ? 'green'
                                    : record.type === 'outbox'
                                        ? 'orange'
                                        : 'purple'
                            }
                            style={{ fontSize: '11px' }}
                        >
                            {(String(record.type || 'unknown')).toUpperCase()}
                        </Tag>
                    </Space>
                </Space>
            ),
        },
        {
            title: 'Messages',
            dataIndex: 'messageCount',
            key: 'messageCount',
            sorter: true,
            width: 120,
            render: (value: number) => (
                <Space>
                    <InboxOutlined style={{ color: '#1890ff' }} />
                    <span style={{ fontWeight: 500 }}>{(value ?? 0).toLocaleString()}</span>
                </Space>
            ),
        },
        {
            title: 'Consumers',
            dataIndex: 'consumerCount',
            key: 'consumerCount',
            width: 120,
            render: (value: number) => (
                <Space>
                    <UserOutlined style={{ color: '#52c41a' }} />
                    <span style={{ fontWeight: 500 }}>{value ?? 0}</span>
                </Space>
            ),
        },
        {
            title: 'Message Rate',
            dataIndex: 'messagesPerSecond',
            key: 'messagesPerSecond',
            sorter: true,
            width: 140,
            render: (value: number) => (
                <Space>
                    <SendOutlined style={{ color: '#722ed1' }} />
                    <span>{(value ?? 0).toFixed(1)} msg/s</span>
                </Space>
            ),
        },
        {
            title: 'Error Rate',
            dataIndex: 'errorRate',
            key: 'errorRate',
            width: 120,
            render: (value: number) => {
                const safeValue = value ?? 0;
                const color = safeValue > 0.1 ? 'red' : safeValue > 0.01 ? 'orange' : 'green';
                return <Tag color={color}>{(safeValue * 100).toFixed(2)}%</Tag>;
            },
        },
        {
            title: 'Status',
            dataIndex: 'status',
            key: 'status',
            width: 100,
            render: (status: QueueStatus) => {
                const colors: Record<QueueStatus, string> = {
                    active: 'green',
                    paused: 'orange',
                    idle: 'default',
                    error: 'red',
                };
                const safeStatus = status || 'idle';
                return <Tag color={colors[safeStatus] || 'default'}>{String(safeStatus).toUpperCase()}</Tag>;
            },
        },
        {
            title: 'Created',
            dataIndex: 'createdAt',
            key: 'createdAt',
            width: 150,
            render: (text: string) => new Date(text).toLocaleDateString(),
        },
        {
            title: 'Actions',
            key: 'actions',
            width: 80,
            fixed: 'right' as const,
            render: (_: any, record: Queue) => (
                <Dropdown menu={getActionMenu(record)} trigger={['click']}>
                    <Button type="text" icon={<MoreOutlined />} />
                </Dropdown>
            ),
        },
    ];

    return (
        <div style={{ padding: '0' }}>
            <Space direction="vertical" size="large" style={{ width: '100%' }}>
                {/* Setup scope selector */}
                <SetupScopeBar />

                {/* Summary Statistics */}
                <Row gutter={[16, 16]}>
                    <Col xs={24} sm={12} lg={6}>
                        <StatCard
                            title="Total Queues"
                            value={total}
                            icon={<InboxOutlined />}
                            loading={isLoading}
                            valueStyle={{ color: '#1890ff' }}
                        />
                    </Col>
                    <Col xs={24} sm={12} lg={6}>
                        <StatCard
                            title="Active Queues"
                            value={queues.filter((q) => q.status === 'active').length}
                            icon={<InboxOutlined />}
                            loading={isLoading}
                            valueStyle={{ color: '#52c41a' }}
                        />
                    </Col>
                    <Col xs={24} sm={12} lg={6}>
                        <StatCard
                            title="Total Messages"
                            value={totalMessages}
                            icon={<SendOutlined />}
                            loading={isLoading}
                            valueStyle={{ color: '#722ed1' }}
                        />
                    </Col>
                    <Col xs={24} sm={12} lg={6}>
                        <StatCard
                            title="Avg Rate"
                            value={avgMessageRate}
                            suffix="msg/s"
                            precision={1}
                            icon={<SendOutlined />}
                            loading={isLoading}
                            valueStyle={{ color: '#fa8c16' }}
                        />
                    </Col>
                </Row>

                {/* Filters */}
                <FilterBar
                    searchPlaceholder="Search queues..."
                    searchValue={filters.search}
                    onSearch={handleSearch}
                    filters={[
                        {
                            label: 'Type',
                            value: filters.type,
                            mode: 'multiple',
                            placeholder: 'All Types',
                            options: [
                                { label: 'Native', value: 'NATIVE' },
                                { label: 'Outbox', value: 'OUTBOX' },
                                { label: 'Bitemporal', value: 'BITEMPORAL' },
                            ],
                            onChange: handleTypeFilter,
                        },
                        {
                            label: 'Status',
                            value: filters.status,
                            mode: 'multiple',
                            placeholder: 'All Statuses',
                            options: [
                                { label: 'Active', value: 'ACTIVE' },
                                { label: 'Paused', value: 'PAUSED' },
                                { label: 'Idle', value: 'IDLE' },
                                { label: 'Error', value: 'ERROR' },
                            ],
                            onChange: handleStatusFilter,
                        },
                    ]}
                    onClear={handleClearFilters}
                    extra={
                        <Space>
                            <Button
                                data-testid="refresh-queues-btn"
                                icon={<SyncOutlined spin={isFetching} />}
                                onClick={() => refetch()}
                            >
                                Refresh
                            </Button>
                            <Button
                                data-testid="create-queue-btn"
                                type="primary"
                                icon={<PlusOutlined />}
                                onClick={handleCreateQueue}
                            >
                                Create Queue
                            </Button>
                        </Space>
                    }
                />

                {/* Queue Table */}
                <Card
                    title={`Queues (${total})`}
                    variant="borderless"
                    style={{
                        boxShadow: '0 2px 8px rgba(0,0,0,0.06)',
                    }}
                >
                    <Table<Queue>
                        data-testid="queues-table"
                        columns={columns}
                        dataSource={queues}
                        loading={isLoading || isFetching}
                        rowKey={(record) => `${record.setupId}:${record.queueName}`}
                        pagination={{
                            current: filters.page,
                            pageSize: filters.pageSize,
                            total,
                            showSizeChanger: true,
                            showQuickJumper: true,
                            showTotal: (total, range) => `${range[0]}-${range[1]} of ${total} queues`,
                            onChange: (page, pageSize) => {
                                setFilters((prev) => ({ ...prev, page, pageSize }));
                            },
                        }}
                        onChange={(_pagination, _filters, sorter: any) => {
                            if (sorter.field) {
                                setFilters((prev) => ({
                                    ...prev,
                                    sortBy: sorter.field,
                                    sortOrder: sorter.order === 'ascend' ? 'asc' : 'desc',
                                }));
                            }
                        }}
                        scroll={{ x: 1200 }}
                    />
                </Card>

                {/* Create Queue Modal */}
                <Modal
                    title="Create Queue"
                    open={isModalVisible}
                    onOk={handleModalOk}
                    onCancel={() => setIsModalVisible(false)}
                    width={700}
                >
                    <Form form={form} layout="vertical">
                        {/* Identity */}
                        <Row gutter={16}>
                            <Col span={12}>
                                <Form.Item
                                    name="name"
                                    label="Queue Name"
                                    rules={[{ required: true, message: 'Please enter queue name' }]}
                                >
                                    <Input data-testid="queue-name-input" placeholder="e.g., orders, payments" />
                                </Form.Item>
                            </Col>
                            <Col span={12}>
                                <Form.Item
                                    name="setup"
                                    label={
                                        <Space size={4}>
                                            <span>Setup</span>
                                            <Button
                                                type="text"
                                                size="small"
                                                icon={<ReloadOutlined style={{ fontSize: '12px' }} />}
                                                loading={setupsLoading}
                                                onClick={fetchSetups}
                                                title="Refresh setups"
                                                data-testid="refresh-setups-btn"
                                                style={{ padding: '0 4px', height: '20px' }}
                                            />
                                        </Space>
                                    }
                                    rules={[{ required: true, message: 'Please select setup' }]}
                                >
                                    <Select
                                        data-testid="queue-setup-select"
                                        placeholder="Select setup"
                                        loading={setupsLoading}
                                        notFoundContent={setupsLoading ? 'Loading...' : 'No setups found'}
                                    >
                                        {setups.map(setup => (
                                            <Select.Option key={setup.setupId} value={setup.setupId}>
                                                {setup.setupId} ({setup.schema})
                                            </Select.Option>
                                        ))}
                                    </Select>
                                </Form.Item>
                            </Col>
                        </Row>
                        <Row gutter={16}>
                            <Col span={12}>
                                <Form.Item
                                    name="type"
                                    label="Queue Type"
                                    initialValue="native"
                                    rules={[{ required: true }]}
                                >
                                    <Select data-testid="queue-type-select">
                                        <Select.Option value="native">Native (LISTEN/NOTIFY — low latency)</Select.Option>
                                        <Select.Option value="outbox">Outbox (transactional — exactly-once)</Select.Option>
                                    </Select>
                                </Form.Item>
                            </Col>
                        </Row>

                        <Divider orientation="left" plain style={{ fontSize: 12, color: '#8c8c8c' }}>Delivery</Divider>

                        <Row gutter={16}>
                            <Col span={8}>
                                <Form.Item name="maxRetries" label="Max Retries" initialValue={3}>
                                    <InputNumber min={0} max={100} style={{ width: '100%' }} />
                                </Form.Item>
                            </Col>
                            <Col span={8}>
                                <Form.Item name="visibilityTimeoutSeconds" label="Visibility Timeout (s)" initialValue={300}>
                                    <InputNumber min={1} max={86400} style={{ width: '100%' }} />
                                </Form.Item>
                            </Col>
                            <Col span={8}>
                                <Form.Item name="batchSize" label="Batch Size" initialValue={10}>
                                    <InputNumber min={1} max={1000} style={{ width: '100%' }} />
                                </Form.Item>
                            </Col>
                        </Row>
                        <Row gutter={16}>
                            <Col span={8}>
                                <Form.Item name="pollingIntervalSeconds" label="Polling Interval (s)" initialValue={5}>
                                    <InputNumber min={1} max={3600} style={{ width: '100%' }} />
                                </Form.Item>
                            </Col>
                            <Col span={8}>
                                <Form.Item name="fifoEnabled" label="FIFO Ordering" valuePropName="checked" initialValue={false}>
                                    <Switch />
                                </Form.Item>
                            </Col>
                            <Col span={8}>
                                <Form.Item name="deadLetterEnabled" label="Dead Letter Queue" valuePropName="checked" initialValue={true}>
                                    <Switch />
                                </Form.Item>
                            </Col>
                        </Row>
                        <Row gutter={16}>
                            <Col span={12}>
                                <Form.Item name="deadLetterQueueName" label="DLQ Name (optional)">
                                    <Input placeholder="Leave blank for default" />
                                </Form.Item>
                            </Col>
                        </Row>
                    </Form>
                </Modal>
            </Space>
        </div>
    );
};

export default QueuesPage;
